args.sparql:
SELECT ?time WHERE {
  ?race wdt:P115 wd:Q435479;  # Circuit Gilles Villeneuve
        wdt:P585 ?date;
        wdt:P31 wd:Q82556.  # Formula 1 race
  FILTER(YEAR(?date) IN (2015, 2016))
  ?result wdt:P173 ?race;
          wdt:P106 wd:Q7508;  # Lewis Hamilton
          p:P1134 ?timeStat.
  ?timeStat ps:P1134 ?time;
          pq:P1345 wd:Q1283302.  # Q3 qualifier
} ORDER BY ASC(?time) LIMIT 2

SELECT ?time WHERE {
  ?race wdt:P2888 wd:Q435479;  # Circuit Gilles Villeneuve
        wdt:P585 ?date;
        wdt:P31 wd:Q82556.  # Formula One race
  FILTER(YEAR(?date) IN (2015, 2016))
  ?result wdt:P154 wd:Q7508;  # Lewis Hamilton
          wdt:P173 ?race;
          p:P1134 ?timeStat.
  ?timeStat ps:P1134 ?time;
          pq:P1345 wd:Q1283302.  # Q3 qualifier
} ORDER BY ASC(?time) LIMIT 2

SELECT ?time WHERE {
  wd:Q7508 p:P173 ?participation.
  ?participation ps:P173 ?race.
  ?race wdt:P2888 wd:Q435479;
        wdt:P585 ?date;
        wdt:P31 wd:Q82556.
  FILTER(YEAR(?date) IN (2015, 2016))
  ?participation p:P1134 ?timeStat.
  ?timeStat ps:P1134 ?time;
          pq:P1345 wd:Q1283302.
} ORDER BY ASC(?time)
